//stack-grouping.js

import { d3_max } from '../../../d3-constants';
import { arrayIncludes } from '../../../../utils/zcutils';
import { stack } from '../../../main-zc-init';

/**
 * [getStackGroupIndex description]
 * @param  {Array} array    stackGroup
 * @param  {Number} index    seriesIndex
 * @param  {Function} accessor [description]
 * @return {Number}          [description]
 */
export const getStackGroupIndex = stack.getStackGroupIndex = function getStackGroupIndex(array, index, accessor) {
    if (!array) {
        return 0;
    }

    return d3_max(array, (d, j) => {
        var value = accessor ? accessor(d, j) : d;
        return arrayIncludes(value, index) ? j : 0;
    });
}


export const getSeriesIndex4StackLabel = stack.getSeriesIndex4StackLabel = function getSeriesIndex4StackLabel(encode) {
    return encode.seriesIndices[encode.seriesIndices.length - 1];
}
